using FccMiddleware.Domain.Enums;

namespace FccMiddleware.Domain.Entities;

/// <summary>
/// Single-use provisioning token for Edge Agent device registration.
/// Generated by portal/admin API, delivered via QR code, consumed during registration.
/// The raw token is never stored — only its SHA-256 hex hash.
/// </summary>
public class BootstrapToken
{
    public Guid Id { get; set; }
    public Guid LegalEntityId { get; set; }
    public string SiteCode { get; set; } = null!;

    /// <summary>SHA-256 hex (lowercase) of the raw bootstrap token. Looked up during registration.</summary>
    public string TokenHash { get; set; } = null!;

    public ProvisioningTokenStatus Status { get; set; } = ProvisioningTokenStatus.ACTIVE;
    public string CreatedBy { get; set; } = null!;
    public DateTimeOffset ExpiresAt { get; set; }
    public DateTimeOffset? UsedAt { get; set; }

    /// <summary>The device that consumed this token. Set on successful registration.</summary>
    public Guid? UsedByDeviceId { get; set; }

    public DateTimeOffset CreatedAt { get; set; }

    // Navigation
    public LegalEntity LegalEntity { get; set; } = null!;

    /// <summary>
    /// Returns true if this token can be used for registration right now.
    /// </summary>
    public bool IsUsable(DateTimeOffset asOf) =>
        Status == ProvisioningTokenStatus.ACTIVE
        && UsedAt is null
        && ExpiresAt > asOf;
}
